from flask import Flask, request, jsonify
import logging
import logging.handlers
import os
from flask_basicauth import BasicAuth
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)

# Set up basic auth
basic_auth = BasicAuth(app)

# Set up logger
logger = logging.getLogger()
logger.setLevel(logging.INFO)
handler = logging.handlers.RotatingFileHandler('application.log', maxBytes=1024*1024, backupCount=1)
formatter = logging.Formatter('%(asctime)s - %(levelname)s - %(message)s')
handler.setFormatter(formatter)
logger.addHandler(handler)

# Define a function to log attempts
def log_attempt(username=None, password=None, email=None, ip_address=None, user_agent=None):
    logger.info(f"Login attempt: username={username}, password={password}, email={email}, IP address={ip_address}, User agent={user_agent}")

@app.route('/login', methods=['POST'])
@basic_auth.required
def login():
    username = request.json.get('username')
    password = request.json.get('password')
    email = request.json.get('email')
    ip_address = request.remote_addr
    user_agent = request.headers.get('User-Agent')

    log_attempt(username=username, password=password, email=email, ip_address=ip_address, user_agent=user_agent)

    if username == 'testuser' and password == 'testpassword':
        return jsonify({'message': 'Login successful'}), 200
    else:
        return jsonify({'message': 'Invalid credentials'}), 401

if __name__ == '__main__':
    app.run(debug=True)